'use client';

import { useState } from 'react';
import { ImportResult } from '@/lib/import-export/types';
import { ImportExportManager } from '@/lib/import-export/utils';
import Toast from '@/components/ui/Toast';

interface SectionTemplate {
  id: string;
  name: string;
  type: string;
  category: string;
  description: string;
  previewImage: string;
  usageCount: number;
}

const sectionTemplates: SectionTemplate[] = [
  {
    id: '1',
    name: 'Hero Section',
    type: 'hero',
    category: 'Headers',
    description: 'Large banner with title, subtitle, and CTA buttons',
    previewImage: '🎯',
    usageCount: 8,
  },
  {
    id: '2',
    name: 'Feature Grid',
    type: 'features',
    category: 'Content',
    description: 'Grid layout showcasing key features with icons',
    previewImage: '⭐',
    usageCount: 6,
  },
  {
    id: '3',
    name: 'CTA Section',
    type: 'cta',
    category: 'Actions',
    description: 'Call-to-action with form or buttons',
    previewImage: '🚀',
    usageCount: 12,
  },
  {
    id: '4',
    name: 'Testimonials',
    type: 'testimonials',
    category: 'Social Proof',
    description: 'Customer testimonials in card layout',
    previewImage: '💬',
    usageCount: 4,
  },
  {
    id: '5',
    name: 'FAQ Section',
    type: 'faq',
    category: 'Content',
    description: 'Expandable frequently asked questions',
    previewImage: '❓',
    usageCount: 3,
  },
  {
    id: '6',
    name: 'Stats Section',
    type: 'stats',
    category: 'Data',
    description: 'Display key metrics and statistics',
    previewImage: '📊',
    usageCount: 2,
  },
];

const categories = ['All', 'Headers', 'Content', 'Actions', 'Social Proof', 'Data'];

export default function AdminSections() {
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [searchTerm, setSearchTerm] = useState('');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  const filteredSections = sectionTemplates.filter(section => {
    const matchesCategory = selectedCategory === 'All' || section.category === selectedCategory;
    const matchesSearch = section.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         section.description.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  return (
    <div>
      <div className="flex justify-between items-center mb-8">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white">
            Section Library
          </h1>
          <p className="mt-2 text-gray-600 dark:text-gray-400">
            Manage reusable section templates
          </p>
        </div>
        
        <div className="flex space-x-3">
          <button
            onClick={() => {
              const input = document.createElement('input');
              input.type = 'file';
              input.accept = '.json';
              input.onchange = async (e) => {
                const file = (e.target as HTMLInputElement).files?.[0];
                if (!file) return;
                
                try {
                  const data = await ImportExportManager.parseUploadedFile(file);
                  const validation = ImportExportManager.validateImportData(data);
                  
                  if (!validation.valid) {
                    setToast({ message: 'Invalid file: ' + validation.errors.join(', '), type: 'error' });
                    return;
                  }
                  
                  const response = await fetch('/api/admin/import-export', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                      action: 'import',
                      data,
                      options: { autoImportSections: true, validateData: true }
                    })
                  });
                  
                  const result = await response.json();
                  
                  if (result.success) {
                    setToast({ message: result.message, type: 'success' });
                    setTimeout(() => window.location.reload(), 1000);
                  } else {
                    setToast({ message: result.message, type: 'error' });
                  }
                } catch (error) {
                  setToast({ message: 'Import failed', type: 'error' });
                }
              };
              input.click();
            }}
            className="flex items-center px-3 py-2 text-sm bg-green-600 text-white rounded-lg hover:bg-green-700"
          >
            📁 Import Section
          </button>
          <button className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-medium transition-colors">
            Create New Section
          </button>
        </div>
      </div>

      {/* Search and Filters */}
      <div className="mb-6 space-y-4">
        <div className="flex flex-col sm:flex-row gap-4">
          <div className="flex-1">
            <input
              type="text"
              placeholder="Search sections..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-800 text-gray-900 dark:text-white focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>
        </div>
        
        <div className="flex flex-wrap gap-2">
          {categories.map((category) => (
            <button
              key={category}
              onClick={() => setSelectedCategory(category)}
              className={`px-4 py-2 rounded-lg font-medium transition-colors ${
                selectedCategory === category
                  ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/20 dark:text-blue-400'
                  : 'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-700'
              }`}
            >
              {category}
            </button>
          ))}
        </div>
      </div>

      {/* Section Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredSections.map((section) => (
          <div
            key={section.id}
            className="bg-white dark:bg-gray-800 rounded-lg shadow hover:shadow-lg transition-shadow border border-gray-200 dark:border-gray-700"
          >
            <div className="p-6">
              <div className="flex items-center justify-between mb-4">
                <div className="text-4xl">{section.previewImage}</div>
                <span className="px-2 py-1 text-xs font-medium rounded-full bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-300">
                  {section.category}
                </span>
              </div>
              
              <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-2">
                {section.name}
              </h3>
              
              <p className="text-sm text-gray-600 dark:text-gray-400 mb-4">
                {section.description}
              </p>
              
              <div className="flex items-center justify-between">
                <span className="text-sm text-gray-500 dark:text-gray-400">
                  Used {section.usageCount} times
                </span>
                
                <div className="flex flex-col space-y-2">
                  <div className="flex space-x-2">
                    <button className="text-blue-600 hover:text-blue-800 dark:text-blue-400 dark:hover:text-blue-300 text-sm font-medium">
                      Edit
                    </button>
                    <button className="text-green-600 hover:text-green-800 dark:text-green-400 dark:hover:text-green-300 text-sm font-medium">
                      Preview
                    </button>
                    <button className="text-red-600 hover:text-red-800 dark:text-red-400 dark:hover:text-red-300 text-sm font-medium">
                      Delete
                    </button>
                  </div>
                  <button
                    onClick={() => {
                      const exportData = ImportExportManager.exportSection(section.id);
                      if (exportData) {
                        const blob = ImportExportManager.generateDownloadBlob(exportData);
                        const url = URL.createObjectURL(blob);
                        const a = document.createElement('a');
                        a.href = url;
                        a.download = `section-${section.type}-${Date.now()}.json`;
                        document.body.appendChild(a);
                        a.click();
                        document.body.removeChild(a);
                        URL.revokeObjectURL(url);
                      }
                    }}
                    className="text-xs px-2 py-1 bg-blue-100 text-blue-700 rounded hover:bg-blue-200"
                  >
                    📥 Export
                  </button>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {filteredSections.length === 0 && (
        <div className="text-center py-12">
          <div className="text-6xl mb-4">🔍</div>
          <h3 className="text-lg font-medium text-gray-900 dark:text-white mb-2">
            No sections found
          </h3>
          <p className="text-gray-600 dark:text-gray-400">
            Try adjusting your search or filter criteria
          </p>
        </div>
      )}

      {toast && (
        <Toast
          message={toast.message}
          type={toast.type}
          onClose={() => setToast(null)}
        />
      )}
    </div>
  );
}